it('ne devrait pas supprimer la réservation d\'un autre utilisateur', async () => {
  const booking = await Booking.create({ userId: 'user456', showId: 'show456' });
  const otherUserToken = generateToken({ userId: 'user789', role: 'user' });

  await request(app)
    .delete(`/api/bookings/${booking._id}`)
    .set('Authorization', `Bearer ${otherUserToken}`)
    .expect(403); // Forbidden

  const stillExists = await Booking.findById(booking._id);
  expect(stillExists).not.toBeNull();
});

